const state = {
  count: 0,
  user: {
    name: 'Alice',
    age: 25
  }
};

const handler = {
  set(target, property, value) {
    console.log(`Property '${property}' changed from ${target[property]} to ${value}`);
    target[property] = value;
    return true; // indicates success
  }
};

const proxyState = new Proxy(state, handler);

proxyState.count = 1;          // Logs: Property 'count' changed from 0 to 1
proxyState.user.name = 'Bob';  // Does NOT log because nested object is not proxied

function createDeepProxy(object, handler) {
  const proxy = new Proxy(object, {
    get(target, property, receiver) {
      const value = Reflect.get(target, property, receiver);
      if (value && typeof value === 'object') {
        return createDeepProxy(value, handler);
      }
      return value;
    },
    set(target, property, value, receiver) {
      console.log(`Property '${property.toString()}' changed from ${target[property]} to ${value}`);
      return Reflect.set(target, property, value, receiver);
    }
  });
  return proxy;
}

const deepState = {
  count: 0,
  user: {
    name: 'Alice',
    age: 25
  }
};

const proxyDeepState = createDeepProxy(deepState);

proxyDeepState.count = 5;             // Logs: Property 'count' changed from 0 to 5
proxyDeepState.user.name = 'Charlie'; // Logs: Property 'name' changed from Alice to Charlie

function identity(arg: any): any {
  return arg;
}

const result = identity(5); // result is of type any

function identity<T>(arg: T): T {
  return arg;
}

const num = identity<number>(5); // num is of type number
const str = identity<string>('hello'); // str is of type string

function firstElement<T>(arr: T[]): T | undefined {
  return arr[0];
}

const firstNum = firstElement([1, 2, 3]); // inferred as number
const firstStr = firstElement(['a', 'b', 'c']); // inferred as string

class Container<T> {
  private value: T;

  constructor(value: T) {
    this.value = value;
  }

  getValue(): T {
    return this.value;
  }
}

const numberContainer = new Container<number>(123);
console.log(numberContainer.getValue()); // 123

interface HasLength {
  length: number;
}

function logLength<T extends HasLength>(arg: T): T {
  console.log(arg.length);
  return arg;
}

logLength('hello'); // 5
logLength([1, 2, 3]); // 3
